import{_ as d,o as i,c as s,ag as c}from"./chunks/framework.CAXxHpAX.js";const b=JSON.parse('{"title":"春秋：老子，道家学派创始人。无为而治，顺","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-2.md","filePath":"notes/note-2.md"}'),l={name:"notes/note-2.md"};function v(r,a,e,o,t,n){return i(),s("div",null,[...a[0]||(a[0]=[c('<h1 id="春秋-老子-道家学派创始人。无为而治-顺" tabindex="-1">春秋：老子，道家学派创始人。无为而治，顺 <a class="header-anchor" href="#春秋-老子-道家学派创始人。无为而治-顺" aria-label="Permalink to &quot;春秋：老子，道家学派创始人。无为而治，顺&quot;">​</a></h1><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、春秋：</span>老子，道家学派创始人。无为而治，顺应自然，事物都有对立面，可以相互转化。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>孔子，儒家学派创始人。仁，仁者爱人。以德治国。创办私学，有教无类。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、百家争鸣：</span>战国： 墨家：兼爱非攻尚贤节俭</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">儒家：</span>孟子，仁政，民贵君轻，反对一切非正义战争</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">儒家：</span>荀子，礼治</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">道家：</span>庄子，顺应自然和民心，精神自由，人格独立</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">法家：</span>韩非，以法治国，树立君主权威，建立中央集权专制统治。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">3、百家争鸣的影响：</span>促进了思想和学术的繁荣，成为中国古代第一次思想文化发展的高峰。为中国古代文化的发展奠定了基础，对后世有十分重要的影响。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">4、江南地区开发的根本原因：</span>北人南迁带来了劳动力、技术、工具</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">5、魏晋时期，北方民族交融的表现：</span>胡汉观念淡薄，民族偏见和隔阂减少</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">6、首都：</span>秦：咸阳 西汉：长安 东汉：洛阳</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>7、第一次人口迁徙高潮的事件？西晋八王之乱</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">8、西周分封制（奴隶制）影响：</span>积极：保证了周王朝对地方的控制，稳定了政局，扩大了统治范围。有利于边远地区的开发和民族交融。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">消极：</span>诸侯具有较大独立性，导致了春秋战国的分裂动荡局面。</p></div><div class="circle-overlay"></div></div></div>',15)])])}const y=d(l,[["render",v]]);export{b as __pageData,y as default};
